document.addEventListener("DOMContentLoaded",()=>{async function handleFormSubmit(t){t.preventDefault(),t.stopPropagation();const e={},o=[];document.querySelectorAll(".card-body").forEach(t=>{t.querySelectorAll("input, select, textarea").forEach(t=>{"INPUT"===t.tagName?"checkbox"===t.type?e[t.name]=t.checked:"file"===t.type?t.files.length>0&&o.push(new Promise((o,s)=>{const n=new FileReader;n.onload=s=>{e[t.name]=s.target.result,o()},n.onerror=s,n.readAsDataURL(t.files[0])})):e[t.name]=t.value:"TEXTAREA"===t.tagName?e[t.name]=t.value:"SELECT"===t.tagName&&(t.multiple?e[t.name]=Array.from(t.selectedOptions).map(t=>t.value):e[t.name]=-1===t.selectedIndex?null:t.options[t.selectedIndex].value)})});try{await Promise.all(o);const t=document.getElementById("trapezesId").value,s=document.querySelector('meta[name="csrf-token"]')?.content||"",n=await fetch(`/api/trapezes/update/${t}`,{method:"POST",headers:{"Content-Type":"application/json","CSRF-Token":s},credentials:"include",body:JSON.stringify(e)});if(n.redirected&&n.url)return void(window.location.href=n.url);if(n.status>=300&&n.status<400){const t=n.headers.get("Location")||n.headers.get("location");if(t){const e=t.startsWith("http")?t:new URL(t,window.location.origin).toString();return void(window.location.href=e)}throw new Error(`Redirect ${n.status} χωρίς Location header`)}if(403===n.status)throw new Error("CSRF blocked (403) — η συνεδρία έληξε ή λείπει token.");if(204===n.status)return void await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"success",title:"Επιτυχής ενημέρωση!",timer:1200,showConfirmButton:!1,customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}}).then(()=>window.location.href=`/companies/trapezes/edit/${t}`);if((n.headers.get("content-type")||"").includes("application/json")){const e=await n.json();if(!n.ok||!e?.success)throw new Error(`HTTP ${n.status} / success=${e?.success}`);return void await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"success",title:"Επιτυχής ενημέρωση!",timer:1200,showConfirmButton:!1,customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}}).then(()=>window.location.href=e.redirectUrl||`/companies/trapezes/edit/${t}`)}if(n.ok)return void await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"success",title:"Επιτυχής ενημέρωση!",timer:1200,showConfirmButton:!1,customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}}).then(()=>window.location.href=`/companies/trapezes/edit/${t}`);throw new Error(`HTTP error ${n.status}`)}catch(t){await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"error",title:"Αποτυχία αποθήκευσης",timer:1200,text:String(t?.message||t),showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-error custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}})}}document.querySelectorAll(".submitButton").forEach(t=>{t.addEventListener("click",handleFormSubmit)})});